import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Trash2, ArrowLeft, X, Save, 
  Loader2, Search, CheckCircle2, Upload, ImageIcon, Sparkles, Database, Table as TableIcon 
} from 'lucide-react';

// --- COMPONENTE 1: GALERÍA MAESTRA ---
const ModalGaleria = ({ onClose, cloudName, folder, preset, API_URL }) => {
  const [subiendo, setSubiendo] = useState(false);
  const [log, setLog] = useState([]);

  const subirAFondo = async (e) => {
    const files = Array.from(e.target.files);
    setSubiendo(true);
    
    for (const file of files) {
      const formData = new FormData();
      formData.append('file', file);
      formData.append('upload_preset', preset);
      formData.append('folder', folder);
      
      try {
        const res = await axios.post(`https://api.cloudinary.com/v1_1/${cloudName}/image/upload`, formData);
        
        // Limpiamos el nombre: "Aceite_Natura.jpg" -> "aceite natura"
        const nombreLimpio = file.name.split('.')[0].replace(/[-_.]/g, ' ').toLowerCase();

        const dataImagen = {
          nombreReferencia: nombreLimpio,
          publicId: res.data.public_id,
          url: res.data.secure_url
        };
        
        await axios.post(`${API_URL}/api/galeria`, dataImagen);
        setLog(prev => [...prev, { name: file.name, status: 'ok' }]);
      } catch (err) {
        setLog(prev => [...prev, { name: file.name, status: 'error' }]);
      }
    }
    setSubiendo(false);
  };

  return (
    <div style={modalOverlay}>
      <div style={{...modalContent, width: '500px'}}>
        <div style={modalHeader}>
          <h3><Database size={20} color="#8b5cf6"/> Biblioteca Maestra</h3>
          <button onClick={onClose} style={closeBtn}><X /></button>
        </div>
        <p style={subtitleStyle}>Las fotos que subas aquí servirán para el autocompletado.</p>
        
        <input type="file" multiple onChange={subirAFondo} id="upload-galeria" style={{display:'none'}} />
        <label htmlFor="upload-galeria" style={dropzoneStyle}>
          {subiendo ? <Loader2 className="animate-spin" size={32} color="#8b5cf6" /> : <Upload size={32} color="#94a3b8" />}
          <span style={{marginTop: 10, fontWeight: '600'}}>{subiendo ? 'Procesando archivos...' : 'Click para subir fotos'}</span>
        </label>

        <div style={logContainer}>
          {log.map((l, i) => (
            <div key={i} style={logItem}>
              <span>{l.name}</span> {l.status === 'ok' ? <CheckCircle2 size={14} color="#10b981"/> : <X size={14} color="#ef4444"/>}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

// --- COMPONENTE 2: CARGADOR DE PRODUCTOS (EXCEL STYLE) ---
const ModalCargaExcel = ({ onClose, API_URL, localId, onComplete, cloudName }) => {
  const [filas, setFilas] = useState([{ id: Date.now(), texto: '', precio: '', stock: '', fotoSugerida: null }]);
  const [galeria, setGaleria] = useState([]);
  const [guardando, setGuardando] = useState(false);

  useEffect(() => {
    axios.get(`${API_URL}/api/galeria`).then(res => setGaleria(res.data)).catch(e => console.log("Error galeria:", e));
  }, [API_URL]);

  const buscarMatch = (texto) => {
    if (!texto || texto.length < 3) return null;
    const t = texto.toLowerCase();
    // Match inteligente: busca si todas las palabras ingresadas están en el nombre de la foto
    const palabras = t.split(' ').filter(p => p.length > 1);
    return galeria.find(f => palabras.every(p => f.nombreReferencia.includes(p)));
  };

  const handleChange = (id, field, value) => {
    const nuevas = filas.map(f => {
      if (f.id === id) {
        const actualizado = { ...f, [field]: value };
        if (field === 'texto') actualizado.fotoSugerida = buscarMatch(value);
        return actualizado;
      }
      return f;
    });
    setFilas(nuevas);
  };

  const agregarFila = () => setFilas([...filas, { id: Date.now(), texto: '', precio: '', stock: '', fotoSugerida: null }]);

  const guardarTodo = async () => {
    setGuardando(true);
    try {
      const promesas = filas.map(f => {
        if (!f.texto || !f.precio) return null;
        return axios.post(`${API_URL}/api/ofertas`, {
          producto: f.texto,
          precioNuevo: Number(f.precio),
          precioViejo: Number(f.precio),
          stock: Number(f.stock) || 0,
          publicId: f.fotoSugerida ? f.fotoSugerida.publicId : 'placeholder_id',
          local: localId,
          categoria: 'Almacén',
          publicado: true
        });
      });
      await Promise.all(promesas.filter(p => p !== null));
      onComplete();
      onClose();
    } catch (e) {
      alert("Error al guardar. Verifica que el servidor esté corriendo.");
    } finally {
      setGuardando(false);
    }
  };

  return (
    <div style={modalOverlay}>
      <div style={{...modalContent, width: '950px', maxHeight: '90vh', overflowY: 'auto'}}>
        <div style={modalHeader}>
          <h3><TableIcon size={20} color="#0284c7"/> Carga de Inventario</h3>
          <button onClick={onClose} style={closeBtn}><X /></button>
        </div>
        
        <table style={excelTable}>
          <thead>
            <tr style={excelHeader}>
              <th style={{width: '80px'}}>FOTO</th>
              <th>PRODUCTO / MARCA / PESO</th>
              <th style={{width: '150px'}}>PRECIO $</th>
              <th style={{width: '100px'}}>STOCK</th>
              <th style={{width: '50px'}}></th>
            </tr>
          </thead>
          <tbody>
            {filas.map(f => (
              <tr key={f.id} style={excelRow}>
                <td>
                  <div style={previewBox}>
                    {f.fotoSugerida ? 
                      <img src={`https://res.cloudinary.com/${cloudName}/image/upload/w_100,c_fill/v1/${f.fotoSugerida.publicId}`} style={tableImg} /> 
                      : <ImageIcon size={20} color="#cbd5e1"/>
                    }
                  </div>
                </td>
                <td>
                  <input 
                    style={tableInput} 
                    placeholder="Escribe producto..." 
                    value={f.texto} 
                    onChange={e => handleChange(f.id, 'texto', e.target.value)} 
                  />
                  {f.fotoSugerida && <span style={matchBadge}><Sparkles size={10}/> Foto vinculada</span>}
                </td>
                <td><input style={tableInput} type="number" placeholder="0.00" value={f.precio} onChange={e => handleChange(f.id, 'precio', e.target.value)} /></td>
                <td><input style={tableInput} type="number" placeholder="0" value={f.stock} onChange={e => handleChange(f.id, 'stock', e.target.value)} /></td>
                <td>
                  <button onClick={() => setFilas(filas.filter(row => row.id !== f.id))} style={btnTrash}><Trash2 size={16}/></button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        
        <div style={footerCarga}>
          <button onClick={agregarFila} style={btnSecondary}><Plus size={16}/> Nueva Fila</button>
          <button onClick={guardarTodo} disabled={guardando} style={btnSave}>
            {guardando ? <Loader2 className="animate-spin" size={18}/> : <Save size={18}/>}
            {guardando ? 'Guardando...' : 'Guardar Inventario'}
          </button>
        </div>
      </div>
    </div>
  );
};

// --- COMPONENTE PRINCIPAL ---
const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();
  const [showGaleria, setShowGaleria] = useState(false);
  const [showCarga, setShowCarga] = useState(false);
  const [ofertas, setOfertas] = useState([]);
  
  const API_URL = "http://localhost:5000"; 
  const CLOUD_NAME = "dwpgncjgn";
  const PRESET = "PRODUCTOS";

  const cargarDatos = useCallback(() => {
    axios.get(`${API_URL}/api/ofertas/local/${localId}`).then(res => setOfertas(res.data));
  }, [localId]);

  useEffect(() => { cargarDatos(); }, [cargarDatos]);

  return (
    <div style={containerStyle}>
      <div style={topNav}>
        <button onClick={() => navigate('/dashboard')} style={btnBack}><ArrowLeft size={18}/> Volver al Dashboard</button>
      </div>

      <div style={headerStyle}>
        <div>
          <h1 style={mainTitle}>Gestión de Stock</h1>
          <p style={subtitleStyle}>Paso 1: Sube tus fotos. Paso 2: Carga los precios.</p>
        </div>
        <div style={{display:'flex', gap:'12px'}}>
          <button onClick={() => setShowGaleria(true)} style={btnSecondary}><Database size={18}/> 1. Biblioteca de Fotos</button>
          <button onClick={() => setShowCarga(true)} style={btnPrimary}><Plus size={18}/> 2. Cargar Inventario</button>
        </div>
      </div>

      <div style={gridStyle}>
        {ofertas.length === 0 ? (
          <div style={emptyState}><ImageIcon size={48} color="#e2e8f0"/><p>No hay productos cargados</p></div>
        ) : (
          ofertas.map(o => (
            <div key={o._id} style={itemCard}>
              <div style={imgCardContainer}>
                 <img src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/f_auto,q_auto,w_300/v1/${o.publicId}`} style={imageStyle} alt={o.producto} />
              </div>
              <h4 style={prodTitle}>{o.producto}</h4>
              <div style={priceBadge}>${o.precioNuevo}</div>
              <button style={btnDeleteMini} onClick={async () => {
                if(window.confirm("¿Eliminar?")) { await axios.delete(`${API_URL}/api/ofertas/${o._id}`); cargarDatos(); }
              }}><Trash2 size={12}/> Eliminar</button>
            </div>
          ))
        )}
      </div>

      {showGaleria && <ModalGaleria API_URL={API_URL} cloudName={CLOUD_NAME} preset={PRESET} folder="GALERIA_MAESTRA" onClose={() => setShowGaleria(false)} />}
      {showCarga && <ModalCargaExcel API_URL={API_URL} localId={localId} cloudName={CLOUD_NAME} onComplete={cargarDatos} onClose={() => setShowCarga(false)} />}
    </div>
  );
};

// --- ESTILOS MEJORADOS ---
